import { useState } from "react";
import { useSpeechRecognition, useTTS } from "../../hooks/useSpeech";

export default function SpeakingSection({ speaking: data, onDone, done }) {
  const { speak, speaking } = useTTS();
  const { listening, transcript, error, startListening, stopListening, reset } =
    useSpeechRecognition();
  const [recordings, setRecordings] = useState([]);
  const [showTips, setShowTips] = useState(false);

  function handleRecord() {
    if (listening) stopListening();
    else {
      reset();
      startListening();
    }
  }

  function saveRecording() {
    if (transcript.trim()) {
      setRecordings((r) => [
        ...r,
        { text: transcript, time: new Date().toLocaleTimeString() },
      ]);
      reset();
    }
  }

  return (
    <div className="space-y-4">
      {/* Topic */}
      <div className="bg-white/[0.03] border border-white/[0.07] rounded-xl p-4">
        <p className="text-[11px] font-semibold text-slate-500 uppercase tracking-widest mb-1">
          🎤 Speaking Topic
        </p>
        <p className="text-base font-bold text-white mb-2">"{data.topic}"</p>
        <p className="text-sm text-slate-400 leading-relaxed">{data.prompt}</p>
      </div>

      {/* Example */}
      <div className="bg-white/[0.03] border border-white/[0.07] rounded-xl p-4 flex items-start gap-3">
        <button
          onClick={() => speak(data.example)}
          className={`shrink-0 w-9 h-9 flex items-center justify-center rounded-xl border transition-all text-sm
            ${
              speaking
                ? "bg-violet-600 border-violet-500 text-white"
                : "bg-white/[0.04] border-white/[0.08] text-slate-400 hover:border-violet-500/40 hover:text-violet-300"
            }`}
        >
          🔊
        </button>
        <div>
          <p className="text-[11px] font-semibold text-slate-500 mb-1">
            Example Answer:
          </p>
          <p className="text-sm text-slate-300 italic">"{data.example}"</p>
        </div>
      </div>

      {/* Tips */}
      <div>
        <button
          onClick={() => setShowTips((s) => !s)}
          className="text-xs text-violet-400 font-semibold hover:text-violet-300 transition-colors flex items-center gap-1"
        >
          💡 {showTips ? "Hide Tips" : "Show Speaking Tips"}
        </button>
        {showTips && (
          <div className="mt-2 bg-yellow-500/5 border border-yellow-500/15 rounded-xl p-4">
            <ul className="space-y-1.5">
              {data.tips.map((tip, i) => (
                <li
                  key={i}
                  className="text-xs text-yellow-300/80 flex items-start gap-2"
                >
                  <span className="text-yellow-500 mt-0.5">✦</span>
                  <span>{tip}</span>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>

      {/* Mic */}
      <div className="text-center bg-white/[0.03] border border-white/[0.07] rounded-xl p-6">
        <button
          onClick={handleRecord}
          className={`w-18 h-18 w-[72px] h-[72px] rounded-full flex items-center justify-center mx-auto mb-3 text-2xl transition-all duration-200 border-4 shadow-lg
            ${
              listening
                ? "bg-red-500/20 border-red-400 scale-110 animate-pulse"
                : "bg-violet-600/20 border-violet-500/40 hover:scale-105 hover:bg-violet-600/30"
            }`}
        >
          🎤
        </button>
        <p className="text-xs font-medium text-slate-500">
          {listening
            ? "🔴 Recording... Speak now!"
            : "Click to start recording"}
        </p>
        {error && <p className="text-xs text-red-400 mt-1">{error}</p>}

        {transcript && (
          <div className="mt-4 bg-white/[0.04] border border-white/[0.08] rounded-xl p-3 text-left">
            <p className="text-[11px] font-semibold text-slate-500 mb-1">
              Your answer:
            </p>
            <p className="text-sm text-slate-200">"{transcript}"</p>
            <div className="flex gap-2 mt-2">
              <button
                onClick={saveRecording}
                className="text-xs bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-1.5 rounded-lg font-semibold transition-all"
              >
                Save ✓
              </button>
              <button
                onClick={reset}
                className="text-xs bg-white/[0.06] text-slate-400 px-3 py-1.5 rounded-lg font-semibold hover:bg-white/10 transition-all"
              >
                Clear
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Saved recordings */}
      {recordings.length > 0 && (
        <div>
          <p className="text-[11px] font-semibold text-slate-500 uppercase tracking-widest mb-2">
            Your Recordings
          </p>
          <div className="space-y-2">
            {recordings.map((r, i) => (
              <div
                key={i}
                className="bg-white/[0.03] border border-white/[0.07] rounded-xl p-3 flex items-center gap-3"
              >
                <span className="text-base">🎙️</span>
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-slate-300 truncate">"{r.text}"</p>
                  <p className="text-[11px] text-slate-600">{r.time}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {!done ? (
        <div className="flex justify-end">
          <button
            onClick={onDone}
            className="bg-violet-600 hover:bg-violet-500 text-white font-semibold px-6 py-2.5 rounded-xl text-sm transition-all duration-200 hover:-translate-y-0.5 shadow-lg shadow-violet-900/30"
          >
            Mark as Done ✓
          </button>
        </div>
      ) : (
        <p className="text-right text-emerald-400 font-semibold text-sm">
          ✓ Speaking completed!
        </p>
      )}
    </div>
  );
}
